class Solution:
    def validateBinaryTreeNodes(self, n, leftChild, rightChild):
        """
        :type n: int
        :type leftChild: List[int]
        :type rightChild: List[int]
        :rtype: bool
        """
        # Each node can have at most one parent
        in_degree = [0] * n

        for child in leftChild:
            if child != -1:
                in_degree[child] += 1

        for child in rightChild:
            if child != -1:
                in_degree[child] += 1

        # Exactly one root (in_degree = 0)
        root_count = sum(1 for d in in_degree if d == 0)
        if root_count != 1:
            return False

        # Check for cycle: should have exactly n-1 edges (tree property)
        # Total edges from parents
        total_edges = sum(1 for c in leftChild if c != -1) + sum(1 for c in rightChild if c != -1)

        if total_edges != n - 1:
            return False

        # Any node with in_degree > 1 means multiple parents
        if any(d > 1 for d in in_degree):
            return False

        return True
